528	\begin{lemma}[(i.c) Freeness of the relative cotangent of $G$]
529	  \label{lem:GrpObj_omega_free}
530	  \lean{AlgebraicGeometry.GrpObj.omega_free}
531	  \uses{lem:GrpObj_cotangentSpace, lem:GrpObj_mulRight_globalises}
532	  \notready
533	  The relative cotangent presheaf $\Omega_{G/k}$ is a free $\mathcal O_{G}$-module.
534	\end{lemma}
535	
536	\begin{proof}
537	  \uses{lem:GrpObj_cotangentSpace, lem:GrpObj_mulRight_globalises}
538	  By \cref{lem:GrpObj_mulRight_globalises}, $\Omega_{G/k}$ is canonically isomorphic to the pullback along the structure map $G \to \Spec k$ of the $k$-vector space $\mathfrak g^{\vee} = \eta_{G}^{*}\,\Omega_{G/k}$. By \cref{lem:GrpObj_cotangentSpace}, $\mathfrak g^{\vee}$ is a finitely generated free $k$-module. The pullback of a finitely generated free $k$-module along the structure morphism is a finitely generated free $\mathcal O_{G}$-module.
539	\end{proof}
