541	\begin{lemma}[(i.c) Rank of the relative cotangent of $G$]
542	  \label{lem:GrpObj_omega_rank_eq_dim}
543	  \lean{AlgebraicGeometry.GrpObj.omega_rank_eq_dim}
544	  \uses{lem:GrpObj_omega_free, lem:GrpObj_lieAlgebra_finrank}
545	  \notready
546	  The (constant) rank of $\Omega_{G/k}$ as a free $\mathcal O_{G}$-module equals $n$, where $n$ is the relative dimension supplied by $[\mathtt{SmoothOfRelativeDimension}\,n\,G.\mathtt{hom}]$.
547	\end{lemma}
548	
549	\begin{proof}
550	  \uses{lem:GrpObj_omega_free, lem:GrpObj_lieAlgebra_finrank}
551	  The rank of the pulled-back bundle equals the $k$-dimension of its fibre. The fibre is $\mathfrak g^{\vee}$, whose $k$-rank equals $n$ by \cref{lem:GrpObj_lieAlgebra_finrank}.
552	\end{proof}
